const rows = $input.all().map((item) => {
  const r = item.json || {};
  const emails = (r.all_emails || '').toString().trim();
  const cats = (r.all_categories || '').toString().trim();
  const rating = Number(r.review_rating) || 0;
  const reviews = Number(r.review_count) || 0;
  const hasEmail = emails ? 1 : 0;
  const hasWebsite = r.website ? 1 : 0;
  // simple lead score: rating * log(reviews+1) + email/website boosts, scaled to ~0-100
  const score = Math.round(Math.min(100, rating * Math.log10(reviews + 1) * 12 + hasEmail * 15 + hasWebsite * 5));
  return {
    json: {
      search_rank: r.search_rank ?? '',
      title: r.title || '',
      phone: r.phone || '',
      website: r.website || '',
      emails: emails,
      primary_category: r.primary_category || '',
      categories: cats,
      review_rating: r.review_rating ?? '',
      review_count: r.review_count ?? '',
      status: r.status || '',
      city: r.city || '',
      state: r.state || '',
      address: r.address || '',
      latitude: r.latitude ?? '',
      longitude: r.longitude ?? '',
      place_url: r.url || '',
      lead_score: score,
      source_keyword: r.source_keyword || '',
      source_location: r.source_location || '',
      scraped_at: r.scraped_at || ''
    }
  };
});
return rows.sort((a, b) => b.json.lead_score - a.json.lead_score);
